"use strict";(globalThis.webpackChunklearncpp_docs=globalThis.webpackChunklearncpp_docs||[]).push([[3486],{70505(n,r,e){e.r(r),e.d(r,{assets:()=>a,contentTitle:()=>c,default:()=>d,frontMatter:()=>o,metadata:()=>t,toc:()=>p});const t=JSON.parse('{"id":"cpp17/constexpr-if","title":"if constexpr (\u7f16\u8bd1\u671f if)","description":"C++17 if constexpr (\u7f16\u8bd1\u671f if) \u6559\u5b66\u793a\u4f8b","source":"@site/docs/cpp17/05-constexpr-if.md","sourceDirName":"cpp17","slug":"/cpp17/05-constexpr-if","permalink":"/LearnModernCpp/docs/cpp17/05-constexpr-if","draft":false,"unlisted":false,"tags":[{"inline":true,"label":"cpp17","permalink":"/LearnModernCpp/docs/tags/cpp-17"},{"inline":true,"label":"constexpr_if","permalink":"/LearnModernCpp/docs/tags/constexpr-if"}],"version":"current","sidebarPosition":6,"frontMatter":{"sidebar_position":6,"slug":"05-constexpr-if","title":"if constexpr (\u7f16\u8bd1\u671f if)","description":"C++17 if constexpr (\u7f16\u8bd1\u671f if) \u6559\u5b66\u793a\u4f8b","tags":["cpp17","constexpr_if"]},"sidebar":"docs","previous":{"title":"\u6298\u53e0\u8868\u8fbe\u5f0f (Fold Expressions)","permalink":"/LearnModernCpp/docs/cpp17/04-fold-expressions"},"next":{"title":"inline \u53d8\u91cf (Inline Variables)","permalink":"/LearnModernCpp/docs/cpp17/06-inline-variables"}}');var s=e(74848),i=e(28453);const o={sidebar_position:6,slug:"05-constexpr-if",title:"if constexpr (\u7f16\u8bd1\u671f if)",description:"C++17 if constexpr (\u7f16\u8bd1\u671f if) \u6559\u5b66\u793a\u4f8b",tags:["cpp17","constexpr_if"]},c="if constexpr (\u7f16\u8bd1\u671f if)",a={},p=[{value:"\u5b8c\u6574\u6e90\u7801",id:"\u5b8c\u6574\u6e90\u7801",level:2},{value:"\u53c2\u8003\u94fe\u63a5",id:"\u53c2\u8003\u94fe\u63a5",level:2}];function l(n){const r={a:"a",code:"code",h1:"h1",h2:"h2",header:"header",li:"li",p:"p",pre:"pre",ul:"ul",...(0,i.R)(),...n.components};return(0,s.jsxs)(s.Fragment,{children:[(0,s.jsx)(r.header,{children:(0,s.jsx)(r.h1,{id:"if-constexpr-\u7f16\u8bd1\u671f-if",children:"if constexpr (\u7f16\u8bd1\u671f if)"})}),"\n",(0,s.jsx)(r.p,{children:"C++17 \u6807\u51c6\u5f15\u5165\u7684 if constexpr (\u7f16\u8bd1\u671f if) \u7279\u6027\u5b8c\u6574\u6559\u5b66\u793a\u4f8b\u3002"}),"\n",(0,s.jsx)(r.h2,{id:"\u5b8c\u6574\u6e90\u7801",children:"\u5b8c\u6574\u6e90\u7801"}),"\n",(0,s.jsx)(r.pre,{children:(0,s.jsx)(r.code,{className:"language-cpp",metastring:'title="cpp17/05_constexpr_if.cpp"',children:'/**\r\n * ============================================================\r\n * \u7279\u6027\u540d\u79f0: if constexpr (\u7f16\u8bd1\u671f if)\r\n * \u6240\u5c5e\u6807\u51c6: C++17\r\n * ============================================================\r\n *\r\n * [\u662f\u4ec0\u4e48]: \u5728\u7f16\u8bd1\u671f\u6839\u636e\u5e38\u91cf\u8868\u8fbe\u5f0f\u7684\u503c\u9009\u62e9\u6027\u5730\u7f16\u8bd1\u4ee3\u7801\u5206\u652f\u3002\r\n *          \u4e0d\u6ee1\u8db3\u6761\u4ef6\u7684\u5206\u652f\u4f1a\u88ab\u5b8c\u5168\u4e22\u5f03\uff08\u4e0d\u5b9e\u4f8b\u5316\uff09\uff0c\u800c\u975e\u4ec5\u4ec5\r\n *          \u4e0d\u6267\u884c\u3002\r\n *\r\n * [\u4e3a\u4ec0\u4e48\u5f15\u5165]: C++14 \u4e2d\u5b9e\u73b0\u7c7b\u578b\u6d3e\u53d1\u9700\u8981 SFINAE\u3001\u6807\u7b7e\u6d3e\u53d1\u3001\r\n *              \u7279\u5316\u7b49\u590d\u6742\u6280\u5de7\u3002if constexpr \u8ba9\u7f16\u8bd1\u671f\u6761\u4ef6\u5206\u652f\r\n *              \u50cf\u666e\u901a if \u4e00\u6837\u76f4\u89c2\u3002\r\n *\r\n * [\u5173\u952e\u8981\u70b9]:\r\n *   - \u6761\u4ef6\u5fc5\u987b\u662f\u7f16\u8bd1\u671f\u5e38\u91cf\u8868\u8fbe\u5f0f\r\n *   - \u672a\u9009\u4e2d\u7684\u5206\u652f\u4e0d\u4f1a\u88ab\u5b9e\u4f8b\u5316 \u2192 \u53ef\u4ee5\u5305\u542b\u5bf9\u5f53\u524d\u7c7b\u578b\u65e0\u6548\u7684\u4ee3\u7801\r\n *   - \u5e38\u4e0e type_traits (is_integral, is_same \u7b49) \u914d\u5408\u4f7f\u7528\r\n *   - \u53ef\u66ff\u4ee3\u5927\u91cf SFINAE \u548c\u6a21\u677f\u7279\u5316\u4ee3\u7801\r\n *   - \u53ef\u7528\u4e8e\u9012\u5f52\u6a21\u677f\u7ec8\u6b62\u6761\u4ef6\r\n * ============================================================\r\n */\r\n\r\n#include <iostream>\r\n#include <string>\r\n#include <type_traits>\r\n#include <vector>\r\n#include <array>\r\n\r\n// ============================================================\r\n// \u57fa\u7840\u7528\u6cd5\r\n// ============================================================\r\n\r\n// 1. \u6839\u636e\u7c7b\u578b\u9009\u62e9\u4e0d\u540c\u5904\u7406\u65b9\u5f0f\r\ntemplate<typename T>\r\nstd::string type_to_string(T value) {\r\n    if constexpr (std::is_integral_v<T>) {\r\n        return "\u6574\u6570: " + std::to_string(value);\r\n    } else if constexpr (std::is_floating_point_v<T>) {\r\n        return "\u6d6e\u70b9\u6570: " + std::to_string(value);\r\n    } else {\r\n        return "\u5176\u4ed6\u7c7b\u578b";\r\n    }\r\n}\r\n\r\n// 2. \u66ff\u4ee3 SFINAE\r\n//    C++14 SFINAE \u5199\u6cd5\uff1a\r\n//    template<typename T>\r\n//    std::enable_if_t<std::is_integral_v<T>> process(T v) { ... }\r\n//    template<typename T>\r\n//    std::enable_if_t<!std::is_integral_v<T>> process(T v) { ... }\r\n\r\n//    C++17 if constexpr \u5199\u6cd5\uff1a\r\ntemplate<typename T>\r\nvoid process(T value) {\r\n    if constexpr (std::is_integral_v<T>) {\r\n        std::cout << "\u5904\u7406\u6574\u6570: " << value * 2 << "\\n";\r\n    } else if constexpr (std::is_floating_point_v<T>) {\r\n        std::cout << "\u5904\u7406\u6d6e\u70b9: " << value + 0.5 << "\\n";\r\n    } else {\r\n        std::cout << "\u5904\u7406\u5176\u4ed6: " << value << "\\n";\r\n    }\r\n}\r\n\r\nvoid basic_usage() {\r\n    std::cout << "--- basic_usage ---\\n";\r\n\r\n    // \u7c7b\u578b\u5230\u5b57\u7b26\u4e32\r\n    std::cout << type_to_string(42) << "\\n";\r\n    std::cout << type_to_string(3.14) << "\\n";\r\n\r\n    // \u7c7b\u578b\u6d3e\u53d1\u5904\u7406\r\n    process(10);\r\n    process(2.5);\r\n    process(std::string("hello"));\r\n}\r\n\r\n// ============================================================\r\n// \u8fdb\u9636\u7528\u6cd5\r\n// ============================================================\r\n\r\n// 1. \u9012\u5f52\u6a21\u677f\u7ec8\u6b62 \u2014\u2014 \u7f16\u8bd1\u671f\u8ba1\u7b97\u53c2\u6570\u4e2a\u6570\u5e76\u6253\u5370\r\ntemplate<typename T, typename... Rest>\r\nvoid print_values(T first, Rest... rest) {\r\n    std::cout << first;\r\n    if constexpr (sizeof...(rest) > 0) {\r\n        std::cout << ", ";\r\n        print_values(rest...);  // \u9012\u5f52\u5c55\u5f00\r\n    } else {\r\n        std::cout << "\\n";      // \u7ec8\u6b62\u6761\u4ef6\r\n    }\r\n}\r\n\r\n// 2. \u7f16\u8bd1\u671f\u9636\u4e58\r\ntemplate<int N>\r\nconstexpr int factorial() {\r\n    if constexpr (N <= 1) {\r\n        return 1;\r\n    } else {\r\n        return N * factorial<N - 1>();\r\n    }\r\n}\r\n\r\n// 3. \u6839\u636e\u5bb9\u5668\u7c7b\u578b\u9009\u62e9\u904d\u5386\u65b9\u5f0f\r\ntemplate<typename Container>\r\nvoid smart_print(const Container& c) {\r\n    if constexpr (std::is_array_v<std::remove_reference_t<decltype(c)>>) {\r\n        std::cout << "\u539f\u751f\u6570\u7ec4: ";\r\n    } else {\r\n        std::cout << "\u5bb9\u5668(size=" << c.size() << "): ";\r\n    }\r\n    for (const auto& elem : c) {\r\n        std::cout << elem << " ";\r\n    }\r\n    std::cout << "\\n";\r\n}\r\n\r\n// 4. SFINAE \u8f85\u52a9 \u2014\u2014 \u68c0\u6d4b\u7c7b\u578b\u662f\u5426\u6709 .size() \u6210\u5458\r\ntemplate<typename T, typename = void>\r\nstruct has_size : std::false_type {};\r\n\r\ntemplate<typename T>\r\nstruct has_size<T, std::void_t<decltype(std::declval<T>().size())>>\r\n    : std::true_type {};\r\n\r\ntemplate<typename T>\r\nauto get_size(const T& t) {\r\n    if constexpr (has_size<T>::value) {\r\n        return t.size();\r\n    } else {\r\n        return 0;\r\n    }\r\n}\r\n\r\n// 5. \u7c7b\u578b\u5b89\u5168\u7684\u8f6c\u6362\u51fd\u6570\r\ntemplate<typename To, typename From>\r\nTo safe_cast(From value) {\r\n    if constexpr (std::is_same_v<To, From>) {\r\n        // \u76f8\u540c\u7c7b\u578b\uff0c\u76f4\u63a5\u8fd4\u56de\r\n        return value;\r\n    } else if constexpr (std::is_convertible_v<From, To>) {\r\n        // \u53ef\u9690\u5f0f\u8f6c\u6362\r\n        return static_cast<To>(value);\r\n    } else {\r\n        static_assert(std::is_convertible_v<From, To>,\r\n                      "\u65e0\u6cd5\u8f6c\u6362\u7684\u7c7b\u578b!");\r\n        return To{};\r\n    }\r\n}\r\n\r\nvoid advanced_usage() {\r\n    std::cout << "\\n--- advanced_usage ---\\n";\r\n\r\n    // \u9012\u5f52\u6253\u5370\r\n    std::cout << "\u9012\u5f52\u6253\u5370: ";\r\n    print_values(1, "hello", 3.14, \'A\');\r\n\r\n    // \u7f16\u8bd1\u671f\u9636\u4e58\r\n    constexpr int f5 = factorial<5>();\r\n    std::cout << "5! = " << f5 << "\\n";\r\n    constexpr int f10 = factorial<10>();\r\n    std::cout << "10! = " << f10 << "\\n";\r\n\r\n    // \u667a\u80fd\u6253\u5370\u5bb9\u5668\r\n    std::vector<int> v{1, 2, 3};\r\n    smart_print(v);\r\n\r\n    // \u5b89\u5168\u8f6c\u6362\r\n    auto i = safe_cast<int>(3.14);\r\n    std::cout << "safe_cast<int>(3.14) = " << i << "\\n";\r\n    auto s = safe_cast<std::string>(std::string("hello"));\r\n    std::cout << "safe_cast<string>(\\"hello\\") = " << s << "\\n";\r\n}\r\n\r\n// ============================================================\r\n// \u6613\u9519\u70b9 / \u9677\u9631\r\n// ============================================================\r\n\r\n// \u793a\u4f8b\uff1a\u5c55\u793a if constexpr \u7684\u5a01\u529b \u2014\u2014 \u88ab\u4e22\u5f03\u7684\u5206\u652f\u4e0d\u9700\u8981\u5408\u6cd5\r\ntemplate<typename T>\r\nvoid demo_discard(T value) {\r\n    if constexpr (std::is_integral_v<T>) {\r\n        // \u4ec5\u5bf9\u6574\u6570\u7c7b\u578b\u8c03\u7528 value % 2\r\n        std::cout << value << " \u662f" << (value % 2 == 0 ? "\u5076\u6570" : "\u5947\u6570") << "\\n";\r\n    } else {\r\n        // \u5bf9\u4e8e string \u7c7b\u578b\uff0cvalue % 2 \u4e0d\u5408\u6cd5\r\n        // \u4f46\u56e0\u4e3a if constexpr\uff0cstring \u5b9e\u4f8b\u5316\u65f6\u8fd9\u4e2a\u5206\u652f\u88ab\u4e22\u5f03\r\n        std::cout << "\u4e0d\u662f\u6574\u6570\u7c7b\u578b\\n";\r\n    }\r\n}\r\n\r\nvoid pitfalls() {\r\n    std::cout << "\\n--- pitfalls ---\\n";\r\n\r\n    // \u9677\u9631 1: \u6761\u4ef6\u5fc5\u987b\u662f\u7f16\u8bd1\u671f\u5e38\u91cf\r\n    // int x = 5;\r\n    // if constexpr (x > 0) { }  // \u9519\u8bef\uff01x \u4e0d\u662f constexpr\r\n    std::cout << "\u9677\u96311 - \u6761\u4ef6\u5fc5\u987b\u662f\u7f16\u8bd1\u671f\u5e38\u91cf\u8868\u8fbe\u5f0f\\n";\r\n\r\n    // \u9677\u9631 2: if constexpr \u4e0d\u662f #if \u2014\u2014 \u5b83\u4ecd\u7136\u9700\u8981\u8bed\u6cd5\u6b63\u786e\r\n    //         \u88ab\u4e22\u5f03\u7684\u5206\u652f\u5fc5\u987b\u8bed\u6cd5\u6b63\u786e\uff0c\u53ea\u662f\u4e0d\u505a\u8bed\u4e49\u68c0\u67e5\r\n    std::cout << "\u9677\u96312 - \u88ab\u4e22\u5f03\u7684\u5206\u652f\u4ecd\u9700\u8bed\u6cd5\u6b63\u786e\\n";\r\n\r\n    // \u9677\u9631 3: \u5728\u975e\u6a21\u677f\u4e0a\u4e0b\u6587\u4e2d\uff0c\u4e24\u4e2a\u5206\u652f\u90fd\u4f1a\u88ab\u68c0\u67e5\r\n    //         if constexpr \u7684\u300c\u4e22\u5f03\u300d\u7279\u6027\u53ea\u5728\u6a21\u677f\u4e2d\u751f\u6548\r\n    // void non_template_func() {\r\n    //     if constexpr (false) {\r\n    //         // \u8fd9\u91cc\u7684\u4ee3\u7801\u5728\u975e\u6a21\u677f\u51fd\u6570\u4e2d\u4ecd\u7136\u4f1a\u88ab\u7f16\u8bd1\u5668\u68c0\u67e5!\r\n    //     }\r\n    // }\r\n    std::cout << "\u9677\u96313 - \u975e\u6a21\u677f\u51fd\u6570\u4e2d if constexpr \u4e24\u4e2a\u5206\u652f\u90fd\u4f1a\u88ab\u68c0\u67e5\\n";\r\n\r\n    // \u9677\u9631 4: \u5c55\u793a\u88ab\u4e22\u5f03\u5206\u652f\u7684\u5a01\u529b\r\n    demo_discard(42);\r\n    demo_discard(std::string("hello"));\r\n\r\n    // \u9677\u9631 5: \u4e0d\u8981\u6df7\u6dc6 constexpr if \u548c runtime if\r\n    constexpr int N = 10;\r\n    if constexpr (N > 5) {\r\n        std::cout << "\u9677\u96315 - \u7f16\u8bd1\u671f\u786e\u5b9a: N > 5\\n";\r\n    }\r\n    // \u7b49\u4ef7\u4e8e\u76f4\u63a5\u5199 std::cout << "\u7f16\u8bd1\u671f\u786e\u5b9a: N > 5\\n";\r\n    // \u7f16\u8bd1\u5668\u4f1a\u4f18\u5316\u6389\u6761\u4ef6\u5224\u65ad\r\n}\r\n\r\n// ============================================================\r\n// \u4e3b\u51fd\u6570\r\n// ============================================================\r\nint main() {\r\n    std::cout << "===== if constexpr (\u7f16\u8bd1\u671f if) - C++17 =====\\n\\n";\r\n\r\n    basic_usage();\r\n    advanced_usage();\r\n    pitfalls();\r\n\r\n    return 0;\r\n}\n'})}),"\n",(0,s.jsx)(r.h2,{id:"\u53c2\u8003\u94fe\u63a5",children:"\u53c2\u8003\u94fe\u63a5"}),"\n",(0,s.jsxs)(r.ul,{children:["\n",(0,s.jsx)(r.li,{children:(0,s.jsx)(r.a,{href:"https://en.cppreference.com/w/cpp/language/constexpr",children:"cppreference: if constexpr (\u7f16\u8bd1\u671f if)"})}),"\n"]})]})}function d(n={}){const{wrapper:r}={...(0,i.R)(),...n.components};return r?(0,s.jsx)(r,{...n,children:(0,s.jsx)(l,{...n})}):l(n)}},28453(n,r,e){e.d(r,{R:()=>o,x:()=>c});var t=e(96540);const s={},i=t.createContext(s);function o(n){const r=t.useContext(i);return t.useMemo(function(){return"function"==typeof n?n(r):{...r,...n}},[r,n])}function c(n){let r;return r=n.disableParentContext?"function"==typeof n.components?n.components(s):n.components||s:o(n.components),t.createElement(i.Provider,{value:r},n.children)}}}]);